import React, { useState, useEffect, useCallback, useMemo, Suspense } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../App';
import './css/HealthReport.css';
import logoImage from '../assets/aqi.webp';

const LazyChart = React.lazy(() => import('./LazyChart'));

// --- HELPER FUNCTIONS ---
const calculateDistance = (lat1, lon1, lat2, lon2) => {
    if ([lat1, lon1, lat2, lon2].some(v => typeof v !== 'number')) return Infinity;
    const R = 6371; // km
    const dLat = (lat2 - lat1) * Math.PI / 180, dLon = (lon2 - lon1) * Math.PI / 180;
    const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return R * c * 1000;
};

const getAQIColor = (aqi) => {
    if (aqi <= 50) return '#10b981';
    if (aqi <= 100) return '#f59e0b';
    if (aqi <= 150) return '#ef4444';
    return '#7c2d12';
};

const getAQIStatus = (aqi) => {
    if (aqi <= 50) return 'Good';
    if (aqi <= 100) return 'Moderate';
    if (aqi <= 150) return 'Unhealthy';
    return 'Hazardous';
};

const getFriendlyStationName = (stationName) => {
    if (!stationName) return 'Local Monitoring Station';
    return stationName.replace(/lora-v\d|loradev\d/gi, '').replace(/station/gi, '').trim() + ' Area';
};

const getHealthRecommendations = (aqi, healthRiskLevel) => {
    const baseRecommendations = { good: { general: ['Enjoy all outdoor activities'], sensitive: ['Conditions are excellent'] }, moderate: { general: ['Reduce prolonged outdoor exertion'], sensitive: ['Limit outdoor activities'] }, unhealthy: { general: ['Avoid prolonged outdoor activities'], sensitive: ['Stay indoors'] }, hazardous: { general: ['Avoid all outdoor activities'], sensitive: ['Remain indoors, seek medical help if needed'] } };
    let category = 'good';
    if (aqi > 150) category = 'hazardous'; else if (aqi > 100) category = 'unhealthy'; else if (aqi > 50) category = 'moderate';
    const isSensitive = healthRiskLevel === 'High' || healthRiskLevel === 'Critical';
    return { recommendations: isSensitive ? baseRecommendations[category].sensitive : baseRecommendations[category].general, isSensitive, category, isEmergency: category === 'hazardous' || (category === 'unhealthy' && isSensitive) };
};

const getEmergencyContacts = (aqi) => {
    if (aqi <= 100) return null;
    return { primary: { name: 'Kerala Pollution Control Board', number: '0471-2418566', description: '24/7 Air Quality Emergency Hotline' }, medical: { name: 'Medical Emergency', number: '108', description: 'Immediate medical assistance' }, poison: aqi > 150 ? { name: 'Poison Control', number: '1066', description: 'Pollution-related health emergencies' } : null };
};

const calculateInterpolatedAqi = (locationData, stations) => {
    let totalWeight = 0, weightedAqi = 0;
    stations.forEach(station => {
        const distance = calculateDistance(locationData.lat, locationData.lng, station.station_info.lat, station.station_info.lng);
        const safeDistance = Math.max(distance, 0.001);
        const weight = 1.0 / (safeDistance ** 2);
        totalWeight += weight;
        weightedAqi += (station.highest_sub_index || 0) * weight;
    });
    return totalWeight > 0 ? Math.round(weightedAqi / totalWeight) : stations[0]?.highest_sub_index || 50;
};


function HealthReport() {
    // --- STATE MANAGEMENT ---
    const { user, loading: authLoading } = useAuth();
    const [reportData, setReportData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [currentTime, setCurrentTime] = useState(new Date());
    const [userLocation, setUserLocation] = useState(null);
    const [currentDataInfo, setCurrentDataInfo] = useState(null);
    const [nearestStation, setNearestStation] = useState(null);

    const navigate = useNavigate();
    const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

    // --- DATA FETCHING & LOGIC ---
    useEffect(() => {
        // CORRECT: Wait for authentication to finish before doing anything.
        if (authLoading) {
            return;
        }

        // CORRECT: If not logged in after check, redirect to login page.
        if (!user) {
            navigate('/login');
            return;
        }

        // CORRECT: Only fetch data if we have a user and haven't fetched yet.
        const fetchReportData = async () => {
            try {
                const response = await fetch(`${API_BASE_URL}/api/health-report/?username=${user.name}`);
                if (!response.ok) {
                    throw new Error("Failed to fetch health report. Please try logging in again.");
                }
                const data = await response.json();
                setReportData(data);
            } catch (err) {
                setError(err.message);
                setLoading(false);
            }
        };

        if (!reportData) {
            fetchReportData();
        }

        navigator.geolocation?.getCurrentPosition(
            (pos) => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
            () => setUserLocation(null)
        );
    }, [user, authLoading, navigate, reportData, API_BASE_URL]);

    useEffect(() => {
        // CORRECT: Process data only after it has been fetched.
        if (!reportData?.stations) return;

        const stationEntries = Object.entries(reportData.stations);
        if (stationEntries.length === 0) {
            setError("No monitoring station data available.");
            setLoading(false);
            return;
        }

        const stationsList = Object.values(reportData.stations);
        const [defaultStationId, defaultStation] = stationEntries[0];
        
        let nearestStationInfo = { id: defaultStationId, distance: null, ...defaultStation };
        
        if (userLocation) {
            let nearestDist = Infinity;
            stationEntries.forEach(([id, station]) => {
                const dist = calculateDistance(userLocation.lat, userLocation.lng, station.station_info.lat, station.station_info.lng);
                if (dist < nearestDist) {
                    nearestDist = dist;
                    nearestStationInfo = { id, distance: nearestDist, ...station };
                }
            });
        }
        setNearestStation(nearestStationInfo);
        
        let aqiToDisplay, stationNameToDisplay, isInterpolated = false;

        if (userLocation && nearestStationInfo.distance !== null && nearestStationInfo.distance <= 2000) { // Using a 2km radius for interpolation
            aqiToDisplay = calculateInterpolatedAqi(userLocation, stationsList);
            stationNameToDisplay = "Your Exact Location";
            isInterpolated = true;
        } else {
            aqiToDisplay = nearestStationInfo.highest_sub_index;
            stationNameToDisplay = getFriendlyStationName(nearestStationInfo.station_info.name);
        }

        setCurrentDataInfo({ aqi: aqiToDisplay, station_name: stationNameToDisplay, is_interpolated: isInterpolated });
        setLoading(false);

    }, [reportData, userLocation]);

    // --- RENDER LOGIC ---

    // CORRECT: Show a loading screen until all data is ready to prevent crashes.
    if (loading) {
        return <div className="panel-loader"><h2>🏥 Generating Your Health Report...</h2><div className="loading-spinner"></div></div>;
    }

    if (error) {
        return <div className="error-message"><h2>⚠️ Error</h2><p>{error}</p><button onClick={() => navigate('/dashboard')} className="retry-btn">📊 Go to Dashboard</button></div>;
    }

    // This check is critical to prevent crashes before data is fully processed.
    if (!reportData || !currentDataInfo || !nearestStation) {
        return <div className="panel-loader"><h2>Processing data...</h2><div className="loading-spinner"></div></div>;
    }

    // Safely derive values for rendering
    const { health_assessment, forecasts } = reportData;
    const displayAqi = currentDataInfo.aqi;
    const aqiStatus = getAQIStatus(displayAqi);
    const aqiColor = getAQIColor(displayAqi);
    const recommendations = getHealthRecommendations(displayAqi, health_assessment.risk_level);
    const forecastForNearest = forecasts[nearestStation.id];
    const emergencyContacts = getEmergencyContacts(displayAqi);

    return (
        <div className="report-page">
            <nav className="navbar">
                <div className="navbar-content">
                    <Link to="/" className="navbar-brand">
                        <img src={logoImage} alt="AirAware Logo" width="40" height="40" />
                        AirAware
                    </Link>
                    <ul className={`nav-links ${isMenuOpen ? 'active' : ''}`}>
                       <li><Link to="/dashboard" className="nav-link">🏠 Dashboard</Link></li>
                       <li><Link to="/map" className="nav-link">🗺️ Live Map</Link></li>
                       <li><button onClick={() => navigate('/login', { replace: true })} className="nav-link login-btn">🚪 Logout</button></li>
                    </ul>
                </div>
            </nav>

            <div className={`alert-banner ${aqiStatus.toLowerCase()}`} style={{ borderBottom: `3px solid ${aqiColor}` }}>
                <span><strong>CURRENT AIR QUALITY:</strong> {currentDataInfo.station_name} AQI is {Math.round(displayAqi)} - {aqiStatus}</span>
            </div>

            <div className="report-container">
                <div className="header-section">
                    <h1>🏥 Official Air Quality Health Report</h1>
                    <p>Personalized health assessment based on your location and health profile.</p>
                </div>

                <div className="executive-summary">
                     <h2 className="section-title">📋 Executive Health Summary</h2>
                     <div className="overview-grid">
                        <div className="overview-card health-card">
                            <h4>👤 Your Health Profile</h4>
                            <div className="health-score">{health_assessment.score}</div>
                            <div className={`risk-level ${health_assessment.risk_level.toLowerCase()}`}>{health_assessment.risk_level} Risk</div>
                        </div>
                        <div className="overview-card aqi-card">
                            <h4>🌬️ Current Air Quality</h4>
                            <div className="station-name">
                                {currentDataInfo.is_interpolated ? '🎯 Your Location' : `📍 ${currentDataInfo.station_name}`}
                            </div>
                            <div className="station-aqi" style={{ color: aqiColor }}>{Math.round(displayAqi)}</div>
                            <div className="aqi-status-badge" style={{ backgroundColor: aqiColor + '20', color: aqiColor }}>{aqiStatus}</div>
                        </div>
                     </div>
                </div>

                <div className="recommendations-section">
                    <h2 className="section-title">💡 Personalized Health Recommendations</h2>
                     <div className="recommendations-grid">
                        {recommendations?.recommendations.map((action, index) => (
                            <div key={index} className={`recommendation-card ${recommendations.category}`}>
                                <div className="rec-text">{action}</div>
                            </div>
                        ))}
                    </div>
                </div>
                
                {emergencyContacts && (
                    <div className="emergency-contacts-section">
                        <h2 className="section-title">🆘 Emergency Health Contacts</h2>
                        <div className="emergency-contacts-grid">
                             <div className="emergency-contact-card primary"><div className="contact-icon">📞</div><div className="contact-info"><div className="contact-name">{emergencyContacts.primary.name}</div><div className="contact-number">{emergencyContacts.primary.number}</div></div></div>
                             <div className="emergency-contact-card medical"><div className="contact-icon">🏥</div><div className="contact-info"><div className="contact-name">{emergencyContacts.medical.name}</div><div className="contact-number">{emergencyContacts.medical.number}</div></div></div>
                        </div>
                    </div>
                )}

                <div className="dashboard-grid">
                    <div className="dashboard-card forecast-card">
                        <h3>📊 4-Day Air Quality Forecast</h3>
                         <div className="forecast-chart-container">
                            <Suspense fallback={<div className="panel-loader">📊 Loading forecast...</div>}>
                                <LazyChart forecastData={forecastForNearest?.data} selectedParameter={'pm25'} />
                            </Suspense>
                        </div>
                    </div>
                     <div className="dashboard-card health-details-card">
                        <h3>📋 Your Health Profile Details</h3>
                         <div className="health-details-list">
                            {health_assessment.details && Object.entries(health_assessment.details).map(([key, value]) => (
                                <div key={key} className="health-detail-item">
                                    <div className="detail-label">{key.replace(/_/g, ' ')}:</div>
                                    <div className="detail-value">{String(value)}</div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            <footer className="footer">
                <div className="footer-container">
                    <div className="footer-content">
                        <div className="footer-section">
                            <h4>AirAware Kerala</h4>
                            <p>Smart Air Quality Monitoring System</p>
                        </div>
                        <div className="footer-section">
                            <h4>Quick Links</h4>
                            <ul>
                                <li><Link to="/">🏠 Home</Link></li>
                                <li><Link to="/dashboard">📊 Dashboard</Link></li>
                                <li><Link to="/map">🗺️ Live Map</Link></li>
                            </ul>
                        </div>
                        <div className="footer-section">
                            <h4>Contact Information</h4>
                            <p>Adi Shankara Institute of Engineering and Technology</p>
                            <p><strong>Email:</strong> aiiot@adishankara.ac.in</p>
                        </div>
                    </div>
                    <div className="footer-bottom">
                        <p>&copy; {new Date().getFullYear()} AirAware Kerala - Smart Air Quality Monitoring System</p>
                    </div>
                </div>
            </footer>
        </div>
    );
}

export default HealthReport;
